import { useEffect, useState } from "react";

// For a "top-notch" look, I recommend adding the 'Inter' or 'Poppins' font in your index.html
const App = () => {
  const [questions, setQuestions] = useState([]);
  const [selected, setSelected] = useState({});
  const [hovered, setHovered] = useState(null);

  useEffect(() => {
    // Mocking the fetch for demonstration
    // fetch("http://localhost:3000/api/quiz") ...
    setQuestions([
      { id: 1, question: "What is the primary use of a mmWave Radar sensor?", options: ["Measuring Humidity", "Detecting Stationary Presence", "Calculating Soil pH", "Measuring Wind Speed"] },
      { id: 2, question: "Which protocol is commonly used for Digital Light Sensors?", options: ["I2C", "SATA", "MIDI", "POP3"] }
    ]);
  }, []);

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  const progress = Math.round((Object.keys(selected).length / questions.length) * 100) || 0;

  return (
    <div style={styles.container}>
      {/* Animated Background Blobs */}
      <div style={styles.blob1}></div>
      <div style={styles.blob2}></div>

      <div style={styles.contentWrapper}>
        {/* TOP BAR / PROGRESS */}
        <header style={styles.header}>
          <div>
            <h1 style={styles.title}>Quizzly <span style={styles.versionTag}>PRO</span></h1>
            <p style={styles.subtitle}>Harshith B • 23MIS0012</p>
          </div>
          <div style={styles.progressContainer}>
            <div style={styles.progressText}>{progress}% Completed</div>
            <div style={styles.progressBarBg}>
              <div style={{ ...styles.progressBarFill, width: `${progress}%` }}></div>
            </div>
          </div>
        </header>

        {/* MAIN QUIZ AREA */}
        <main style={styles.quizGrid}>
          {questions.map((q, index) => (
            <div key={q.id} style={styles.questionCard}>
              <div style={styles.questionHeader}>
                <span style={styles.questionNumber}>0{index + 1}</span>
                <p style={styles.questionText}>{q.question}</p>
              </div>

              <div style={styles.optionsGrid}>
                {q.options.map((opt) => {
                  const isSelected = selected[q.id] === opt;
                  const isHovered = hovered === `${q.id}-${opt}`;

                  return (
                    <button
                      key={opt}
                      onMouseEnter={() => setHovered(`${q.id}-${opt}`)}
                      onMouseLeave={() => setHovered(null)}
                      onClick={() => handleSelect(q.id, opt)}
                      style={{
                        ...styles.optionBtn,
                        ...(isSelected ? styles.optionSelected : {}),
                        ...(isHovered && !isSelected ? styles.optionHover : {}),
                      }}
                    >
                      <div style={{
                        ...styles.radio,
                        borderColor: isSelected ? "#6366f1" : "rgba(255,255,255,0.3)"
                      }}>
                        {isSelected && <div style={styles.radioInner}></div>}
                      </div>
                      {opt}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </main>
      </div>
    </div>
  );
};

// Styles Object - "The Designer Touch"
const styles = {
  container: {
    minHeight: "100vh",
    backgroundColor: "#0f172a", // Slate 900
    color: "#f8fafc",
    fontFamily: "'Inter', system-ui, sans-serif",
    padding: "40px 20px",
    position: "relative",
    overflowX: "hidden",
  },
  contentWrapper: {
    maxWidth: "900px",
    margin: "0 auto",
    position: "relative",
    zIndex: 10,
  },
  /* Background Aesthetics */
  blob1: {
    position: "absolute",
    top: "-10%",
    left: "-10%",
    width: "400px",
    height: "400px",
    background: "linear-gradient(135deg, #6366f1 0%, #a855f7 100%)",
    filter: "blur(80px)",
    opacity: 0.15,
    borderRadius: "50%",
  },
  blob2: {
    position: "absolute",
    bottom: "10%",
    right: "-5%",
    width: "350px",
    height: "350px",
    background: "linear-gradient(135deg, #0ea5e9 0%, #22d3ee 100%)",
    filter: "blur(80px)",
    opacity: 0.1,
    borderRadius: "50%",
  },
  /* Header Section */
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "60px",
    padding: "0 10px",
  },
  title: {
    fontSize: "32px",
    fontWeight: "800",
    margin: 0,
    letterSpacing: "-0.5px",
  },
  versionTag: {
    fontSize: "12px",
    background: "rgba(99, 102, 241, 0.2)",
    color: "#818cf8",
    padding: "4px 8px",
    borderRadius: "6px",
    verticalAlign: "middle",
    marginLeft: "8px",
    border: "1px solid rgba(99, 102, 241, 0.3)",
  },
  subtitle: {
    color: "#94a3b8",
    marginTop: "5px",
    fontSize: "14px",
  },
  progressContainer: {
    textAlign: "right",
    width: "200px",
  },
  progressText: {
    fontSize: "12px",
    color: "#94a3b8",
    marginBottom: "8px",
    fontWeight: "600",
    textTransform: "uppercase",
  },
  progressBarBg: {
    height: "6px",
    background: "rgba(255,255,255,0.1)",
    borderRadius: "10px",
    overflow: "hidden",
  },
  progressBarFill: {
    height: "100%",
    background: "linear-gradient(90deg, #6366f1, #a855f7)",
    transition: "width 0.5s cubic-bezier(0.4, 0, 0.2, 1)",
  },
  /* Cards */
  quizGrid: {
    display: "flex",
    flexDirection: "column",
    gap: "30px",
  },
  questionCard: {
    background: "rgba(30, 41, 59, 0.7)", // Slate 800 with transparency
    backdropFilter: "blur(16px)",
    border: "1px solid rgba(255, 255, 255, 0.1)",
    borderRadius: "24px",
    padding: "32px",
    boxShadow: "0 20px 25px -5px rgba(0, 0, 0, 0.2)",
  },
  questionHeader: {
    display: "flex",
    gap: "20px",
    marginBottom: "25px",
  },
  questionNumber: {
    fontSize: "14px",
    fontWeight: "700",
    color: "#6366f1",
    background: "rgba(99, 102, 241, 0.1)",
    height: "32px",
    minWidth: "32px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    borderRadius: "8px",
  },
  questionText: {
    fontSize: "20px",
    fontWeight: "600",
    lineHeight: "1.5",
    margin: 0,
    color: "#f1f5f9",
  },
  /* Options */
  optionsGrid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "15px",
  },
  optionBtn: {
    all: "unset",
    display: "flex",
    alignItems: "center",
    padding: "16px 20px",
    borderRadius: "14px",
    cursor: "pointer",
    fontSize: "15px",
    fontWeight: "500",
    background: "rgba(255, 255, 255, 0.03)",
    border: "1px solid rgba(255, 255, 255, 0.08)",
    transition: "all 0.2s ease",
    color: "#cbd5e1",
  },
  optionHover: {
    background: "rgba(255, 255, 255, 0.07)",
    borderColor: "rgba(255, 255, 255, 0.2)",
    transform: "translateY(-2px)",
  },
  optionSelected: {
    background: "rgba(99, 102, 241, 0.15)",
    borderColor: "#6366f1",
    color: "#fff",
    boxShadow: "0 0 20px rgba(99, 102, 241, 0.2)",
  },
  radio: {
    width: "18px",
    height: "18px",
    border: "2px solid",
    borderRadius: "50%",
    marginRight: "15px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    transition: "all 0.2s ease",
  },
  radioInner: {
    width: "10px",
    height: "10px",
    background: "#6366f1",
    borderRadius: "50%",
  }
};

export default App;
